export const docsGuide = {"categories":[{"title":"Getting started","stories":[{"id":"create-identity","title":"Create your identity","introHtml":"<p>Register a WebAuthn passkey — no password, ever. Your OpenApe ID becomes the DDISA authority for your identity: every Service Provider logs you in via DNS-discovered SSO without ever seeing a credential.</p>\n","steps":[{"title":"Open OpenApe ID","html":"The landing page asks for nothing but your email. Click <strong>Create account</strong> to start.","shot":"/docs/screenshots/create-identity/01-landing.png"},{"title":"Request your registration link","html":"Enter your email — OpenApe ID sends you a one-time registration link.","shot":"/docs/screenshots/create-identity/02-request-link.png"},{"title":"Register your passkey","html":"The link opens the passkey ceremony. Your device (Touch ID, Windows Hello, a security key) creates the credential — in this E2E run a virtual authenticator answers headlessly.","shot":"/docs/screenshots/create-identity/03-register-passkey.png"},{"title":"Done — you are signed in","html":"That&#39;s the whole sign-up: one passkey, no password to remember or leak.","shot":"/docs/screenshots/create-identity/04-registered.png"}]}]},{"title":"Account","stories":[{"id":"account-dashboard","title":"Your account — one page per thing","introHtml":"<p>The dashboard is home base for your identity. Every button opens a focused page that shows exactly what it names — passkeys, SSH keys, connected services, delegations — rather than one long settings dump.</p>\n","steps":[{"title":"Your dashboard","html":"Signed in, the root page is your hub: <strong>Passkeys</strong>, <strong>SSH-Keys</strong>, <strong>Agents</strong>, <strong>Berechtigungen</strong>, <strong>Delegationen</strong> and <strong>Verbundene Dienste</strong> — each its own button leading to its own page.","shot":"/docs/screenshots/account-dashboard/01-dashboard.png"},{"title":"Passkeys — just your passkeys","html":"<strong>Passkeys verwalten</strong> opens <em>only</em> your passkeys — add a device, remove an old one. Nothing else on the page.","shot":"/docs/screenshots/account-dashboard/02-passkeys.png"},{"title":"SSH keys — just your keys","html":"<strong>SSH-Keys verwalten</strong> is only your SSH public keys for <em>Sign in with SSH Key</em> — paste one, remove one.","shot":"/docs/screenshots/account-dashboard/03-ssh-keys.png"},{"title":"Connected services — just your consents","html":"<strong>Verbundene Dienste</strong> lists the apps you approved at sign-in. Revoke one and it asks for consent again next time. (Your <strong>Delegationen</strong> — apps acting for you at <em>another</em> service — get their own page too.)","shot":"/docs/screenshots/account-dashboard/04-connected-services.png"}]}]},{"title":"Agents","stories":[{"id":"agent-identities","title":"Your agent identities","introHtml":"<p>Agents are first-class identities under your account: the IdP mints them a DDISA email and you stay in control.</p>\n","steps":[{"title":"Open Agents at your IdP","html":"Every agent spawned from your nests appears here with its own <code>…@id.openape.ai</code> identity — inspect it, or revoke it independently of your own keys.","shot":"/docs/screenshots/agent-identities/01-agents.png"}]}]}]}
